// Extract & normalize input
const body = $input.first().json.body;
const avatar = body.avatar || 'angel';
const stats = body.stats || { health: 80, happiness: 75, wealth: 40, morality: 70 };
const karma = body.karma || 75;
const day = body.day || 1;
const chapter = body.chapter || 1;
const age = body.age || 16;
const name = body.name || 'Inconnu';
const city = body.city || 'Paris';
const history = body.history || [];

// ============ DEATH RISK CALCULATION ============
let baseDeathRisk = 0;
// Age-based mortality curve
if (age < 20) baseDeathRisk = 0.2;
else if (age < 30) baseDeathRisk = 0.5;
else if (age < 50) baseDeathRisk = 1.5;
else if (age < 65) baseDeathRisk = 4;
else if (age < 75) baseDeathRisk = 10;
else if (age < 85) baseDeathRisk = 25;
else baseDeathRisk = 50;

// Health penalty
if (stats.health < 20) baseDeathRisk += 15;
else if (stats.health < 40) baseDeathRisk += 5;

// Avatar multiplier
let deathMultiplier = 1.0;
if (avatar === 'neutral') deathMultiplier = 1.1;
else if (avatar === 'fallen') deathMultiplier = 1.5;
else if (avatar === 'devil') deathMultiplier = 2.5;
else if (avatar === 'angel') deathMultiplier = 0.7;

const finalDeathRisk = Math.min(baseDeathRisk * deathMultiplier, 95);
const deathRoll = Math.random() * 100;
const isDead = deathRoll < finalDeathRisk;

// ============ HAPPINESS CAP (Angel needs >80%) ============
const angelUnlocked = stats.happiness > 80;

// ============ CHOICE POOL CATEGORY ============
let poolTag = avatar;
if (avatar === 'angel' && !angelUnlocked) poolTag = 'angel_locked';

return [{
  json: {
    avatar, stats, karma, day, chapter, age, name, city, history,
    finalDeathRisk: Math.round(finalDeathRisk * 100) / 100,
    isDead, deathRoll: Math.round(deathRoll * 100) / 100,
    angelUnlocked, poolTag,
    deathMultiplier
  }
}];

