// Merge all GPT outputs into unified format
const input = $input.first().json;
let raw = '';

// Extract the AI message content
if (input.message && input.message.content) {
  raw = input.message.content;
} else if (input.text) {
  raw = input.text;
} else if (typeof input === 'string') {
  raw = input;
} else {
  raw = JSON.stringify(input);
}

// Clean markdown fences
raw = raw.replace(/```json\n?/g, '').replace(/```\n?/g, '').trim();

let parsed;
try {
  parsed = JSON.parse(raw);
} catch(e) {
  // Fallback
  parsed = {
    narrative: 'Le destin hesite...',
    chapter_title: 'Interlude',
    whisper: 'Patience...',
    choices: [
      { text: 'Attendre et observer', emoji: '👁️', tag: 'neutre', effects: { health: 0, happiness: 0, wealth: 0, morality: 0 }, karma_shift: 0, consequence: 'Rien ne se passe... pour l\'instant.' }
    ]
  };
}

return [{ json: { ...parsed, _parseError: false } }];

// Build final response with all context
const gpt = $('Parse GPT Response').first().json;
const ctx = $('Compute Risk & Context').first().json;

const response = {
  // Story content
  narrative: gpt.narrative || '',
  chapter_title: gpt.chapter_title || '',
  whisper: gpt.whisper || '',
  choices: gpt.choices || [],

  // Meta
  avatar: ctx.avatar,
  day: ctx.day,
  chapter: ctx.chapter,
  age: ctx.age,

  // Risk info (hidden from player but used by frontend)
  _deathRisk: ctx.finalDeathRisk,
  _deathMultiplier: ctx.deathMultiplier,
  _isDead: false,
  _angelUnlocked: ctx.angelUnlocked,

  // Pool info
  _poolTag: ctx.poolTag,
  _poolSize: ctx.avatar === 'angel' ? 200 : ctx.avatar === 'neutral' ? 300 : ctx.avatar === 'fallen' ? 70 : 500
};

return [{ json: response }];

// DEATH response
const ctx = $('Compute Risk & Context').first().json;

const deathCauses = {
  angel: [
    'Une lumiere douce t\'enveloppe... tu pars en paix, entoure de ceux que tu aimes.',
    'Ton coeur s\'arrete doucement dans ton sommeil. Un sourire reste sur ton visage.',
    'Tu t\'eteins paisiblement, baigne dans la lumiere doree du crepuscule.'
  ],
  neutral: [
    'Le temps a fait son oeuvre. Les statistiques ne mentent jamais.',
    'Arret cardiaque. Probabilite calculee: inevitable.',
    'Le corps cede. L\'equation de la vie se resout a zero.'
  ],
  fallen: [
    'L\'overdose t\'emporte dans un reve dont tu ne reviendras pas.',
    'La route etait glissante. La voiture, trop rapide. La nuit, trop sombre.',
    'Le melange etait trop fort. Tu sombres dans un sommeil eternel, presque beau.'
  ],
  devil: [
    'Une balle dans le noir. Celui que tu as trahi t\'a retrouve.',
    'L\'empire s\'effondre, et toi avec. Personne ne pleure le roi dechu.',
    'Le poison dans le verre etait pour quelqu\'un d\'autre. L\'ironie du diable.',
    'Trahi par ton propre lieutenant. Le pouvoir ne souffre pas de faiblesse.'
  ]
};

const causes = deathCauses[ctx.avatar] || deathCauses.neutral;
const cause = causes[Math.floor(Math.random() * causes.length)];

const epitaphs = {
  angel: `${ctx.name} a vecu dans la lumiere. Que son ame trouve le repos eternel.`,
  neutral: `${ctx.name}. Ne(e) a ${ctx.city}. Decede(e) a ${ctx.age} ans. Statistique accomplie.`,
  fallen: `${ctx.name} a danse avec les ombres. La nuit l'a finalement reclame(e).`,
  devil: `${ctx.name} a regne par le feu. Les cendres sont tout ce qui reste.`
};

return [{ json: {
  _isDead: true,
  deathCause: cause,
  epitaph: epitaphs[ctx.avatar] || epitaphs.neutral,
  avatar: ctx.avatar,
  age: ctx.age,
  day: ctx.day,
  stats: ctx.stats,
  karma: ctx.karma,
  name: ctx.name,
  _deathRisk: ctx.finalDeathRisk,
  _deathRoll: ctx.deathRoll
}}];

// Apply chosen effect to stats, handle karma, age progression
const body = $input.first().json.body;
const choice = body.choice; // { effects, karma_shift, consequence }
const stats = body.stats;
const currentKarma = body.karma || 50;
const currentDay = body.day || 1;
const currentChapter = body.chapter || 1;
const currentAge = body.age || 16;
const avatar = body.avatar || 'angel';

// Apply effects with clamping
const newStats = {
  health: Math.max(0, Math.min(100, stats.health + (choice.effects.health || 0))),
  happiness: Math.max(0, Math.min(100, stats.happiness + (choice.effects.happiness || 0))),
  wealth: Math.max(0, Math.min(100, stats.wealth + (choice.effects.wealth || 0))),
  morality: Math.max(0, Math.min(100, stats.morality + (choice.effects.morality || 0)))
};

// Karma shift
let newKarma = Math.max(0, Math.min(100, currentKarma + (choice.karma_shift || 0)));

// Happiness cap for low karma
const happinessCap = newKarma < 20 ? 40 : newKarma < 40 ? 60 : newKarma < 60 ? 80 : 100;
if (newStats.happiness > happinessCap) newStats.happiness = happinessCap;

// Age progression: every 3 chapters = 1 day = some age
let newChapter = currentChapter + 1;
let newDay = currentDay;
let newAge = currentAge;
let dayComplete = false;

if (newChapter > 3) {
  newChapter = 1;
  newDay = currentDay + 1;
  dayComplete = true;
  // Age: roughly 1 year per 3 real days of play
  // In-game: each day = ~6 months of life
  newAge = 16 + Math.floor((newDay - 1) * 0.5);
}

// Health death check
const healthDead = newStats.health <= 0;

return [{ json: {
  stats: newStats,
  karma: newKarma,
  day: newDay,
  chapter: newChapter,
  age: newAge,
  dayComplete,
  healthDead,
  happinessCap,
  consequence: choice.consequence || '',
  avatar
}}];
